361	    @GET
362	    @Path("/{bucket}/{key:.+}")
363	    public Response getObject(@PathParam("bucket") String bucket,
364	                              @PathParam("key") String key,
365	                              @QueryParam("versionId") String versionId,
366	                              @HeaderParam("x-amz-object-attributes") String objectAttributesHeader,
367	                              @HeaderParam("x-amz-max-parts") Integer maxParts,
368	                              @HeaderParam("x-amz-part-number-marker") Integer partNumberMarker,
369	                              @HeaderParam("If-Match") String ifMatch,
370	                              @HeaderParam("If-None-Match") String ifNoneMatch,
371	                              @HeaderParam("If-Modified-Since") String ifModifiedSince,
372	                              @HeaderParam("If-Unmodified-Since") String ifUnmodifiedSince,
373	                              @HeaderParam("Range") String rangeHeader,
374	                              @Context UriInfo uriInfo,
375	                              @Context HttpHeaders httpHeaders) {
376	        try {
377	            if (hasQueryParam(uriInfo, "tagging")) {
378	                return handleGetObjectTagging(bucket, key);
379	            }
380	            if (hasQueryParam(uriInfo, "retention")) {
381	                return handleGetObjectRetention(bucket, key, versionId);
382	            }
383	            if (hasQueryParam(uriInfo, "legal-hold")) {
384	                return handleGetObjectLegalHold(bucket, key, versionId);
385	            }
386	            if (hasQueryParam(uriInfo, "acl")) {
387	                return Response.ok(s3Service.getObjectAcl(bucket, key, versionId)).build();
388	            }
389	            if (hasQueryParam(uriInfo, "attributes")) {
390	                // Merge all x-amz-object-attributes header values (SDK may send multiple lines)
391	                List<String> attrHeaders = httpHeaders.getRequestHeader("x-amz-object-attributes");
392	                String mergedAttributes = attrHeaders != null ? String.join(",", attrHeaders) : objectAttributesHeader;
393	                return handleGetObjectAttributes(bucket, key, versionId,
394	                        mergedAttributes, maxParts, partNumberMarker);
395	            }
396	            if (hasPreconditions(ifMatch, ifNoneMatch, ifModifiedSince, ifUnmodifiedSince)) {
397	                // Fetch metadata only to evaluate preconditions, avoiding loading the full object unnecessarily.
398	                S3Object metadata = s3Service.headObject(bucket, key, versionId);
399	                Response preconditionResponse = checkPreconditions(metadata, ifMatch, ifNoneMatch, ifModifiedSince, ifUnmodifiedSince);
400	                if (preconditionResponse != null) {
401	                    return preconditionResponse;
402	                }
403	            }
404	            S3Object obj = s3Service.getObject(bucket, key, versionId);
405	
406	            if (rangeHeader != null && rangeHeader.startsWith("bytes=")) {
407	                return handleRangeRequest(obj, rangeHeader);
408	            }
409	
410	            var resp = Response.ok(obj.getData())
411	                    .header("Content-Type", obj.getContentType())
412	                    .header("Content-Length", obj.getSize())
413	                    .header("ETag", obj.getETag())
414	                    .header("Last-Modified", RFC_822.format(obj.getLastModified()))
415	                    .header("Accept-Ranges", "bytes");
416	            if (obj.getVersionId() != null) {
417	                resp.header("x-amz-version-id", obj.getVersionId());
418	            }
419	            appendObjectHeaders(resp, obj);
420	            return resp.build();
421	        } catch (AwsException e) {
422	            return xmlErrorResponse(e);
423	        }
424	    }
425	
426	    private Response handleRangeRequest(S3Object obj, String rangeHeader) {
427	        byte[] data = obj.getData();
428	        int totalSize = data.length;
429	        String rangeSpec = rangeHeader.substring("bytes=".length()).trim();
430	
431	        int start, end;
432	        try {
433	            int dash = rangeSpec.indexOf('-');
434	            if (dash < 0) {
435	                return invalidRangeResponse(totalSize);
436	            }
437	            String before = rangeSpec.substring(0, dash);
438	            String after = rangeSpec.substring(dash + 1);
439	            if (before.isEmpty() && after.isEmpty()) {
440	                return invalidRangeResponse(totalSize);
441	            }
442	            if (before.isEmpty()) {
443	                int suffix = Integer.parseInt(after);
444	                if (suffix <= 0) {
445	                    return invalidRangeResponse(totalSize);
446	                }
447	                start = Math.max(0, totalSize - suffix);
448	                end = totalSize - 1;
449	            } else {
450	                start = Integer.parseInt(before);
451	                end = after.isEmpty() ? totalSize - 1 : Math.min(Integer.parseInt(after), totalSize - 1);
452	            }
453	        } catch (NumberFormatException e) {
454	            return invalidRangeResponse(totalSize);
455	        }
456	
457	        if (start < 0 || start >= totalSize || start > end) {
458	            return invalidRangeResponse(totalSize);
459	        }
460	
461	        byte[] rangeData = java.util.Arrays.copyOfRange(data, start, end + 1);
462	        return Response.status(206)
463	                .entity(rangeData)
464	                .header("Content-Type", obj.getContentType())
465	                .header("Content-Length", rangeData.length)
466	                .header("Content-Range", "bytes " + start + "-" + end + "/" + totalSize)
467	                .header("ETag", obj.getETag())
468	                .header("Last-Modified", RFC_822.format(obj.getLastModified()))
469	                .header("Accept-Ranges", "bytes")
470	                .build();
471	    }
472	
473	    private Response invalidRangeResponse(int totalSize) {
474	        String xml = new XmlBuilder()
475	                .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
476	                .start("Error")
477	                .elem("Code", "InvalidRange")
478	                .elem("Message", "The requested range is not satisfiable.")
479	                .elem("RequestId", java.util.UUID.randomUUID().toString())
480	                .end("Error")
481	                .build();
482	        return Response.status(416)
483	                .entity(xml)
484	                .type(MediaType.APPLICATION_XML)
485	                .header("Content-Range", "bytes */" + totalSize)
486	                .build();
487	    }
