520	    @DELETE
521	    @Path("/{bucket}/{key:.+}")
522	    public Response deleteObject(@PathParam("bucket") String bucket,
523	                                 @PathParam("key") String key,
524	                                 @QueryParam("uploadId") String uploadId,
525	                                 @QueryParam("versionId") String versionId,
526	                                 @Context UriInfo uriInfo,
527	                                 @Context HttpHeaders httpHeaders) {
528	        try {
529	            if (hasQueryParam(uriInfo, "tagging")) {
530	                s3Service.deleteObjectTagging(bucket, key);
531	                return Response.noContent().build();
532	            }
533	            if (uploadId != null) {
534	                s3Service.abortMultipartUpload(bucket, key, uploadId);
535	                return Response.noContent().build();
536	            }
537	            boolean bypass = "true".equalsIgnoreCase(
538	                    httpHeaders.getHeaderString("x-amz-bypass-governance-retention"));
539	            S3Object result = s3Service.deleteObject(bucket, key, versionId, bypass);
540	            var resp = Response.noContent();
541	            if (result != null && result.isDeleteMarker()) {
542	                resp.header("x-amz-delete-marker", "true");
543	                resp.header("x-amz-version-id", result.getVersionId());
544	            }
545	            return resp.build();
546	        } catch (AwsException e) {
547	            return xmlErrorResponse(e);
548	        }
549	    }
