576	    @Produces(MediaType.APPLICATION_XML)
577	    public Response handleMultipartPost(@PathParam("bucket") String bucket,
578	                                         @PathParam("key") String key,
579	                                         @QueryParam("uploadId") String uploadId,
580	                                         @QueryParam("versionId") String versionId,
581	                                         @HeaderParam("Content-Type") String contentType,
582	                                         @Context HttpHeaders httpHeaders,
583	                                         @Context UriInfo uriInfo,
584	                                         byte[] body) {
585	        try {
586	            if (hasQueryParam(uriInfo, "uploads")) {
587	                MultipartUpload upload = s3Service.initiateMultipartUpload(bucket, key, contentType,
588	                        extractUserMetadata(httpHeaders), httpHeaders.getHeaderString("x-amz-storage-class"));
589	                String xml = new XmlBuilder()
590	                        .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
591	                        .start("InitiateMultipartUploadResult", AwsNamespaces.S3)
592	                        .elem("Bucket", bucket)
593	                        .elem("Key", key)
594	                        .elem("UploadId", upload.getUploadId())
595	                        .end("InitiateMultipartUploadResult")
596	                        .build();
597	                return Response.ok(xml).build();
598	            }
599	
600	            if (hasQueryParam(uriInfo, "restore")) {
601	                s3Service.restoreObject(bucket, key, versionId, new String(body, StandardCharsets.UTF_8));
602	                return Response.accepted().build();
603	            }
604	
605	            if (hasQueryParam(uriInfo, "select")) {
606	                S3Object obj = s3Service.getObject(bucket, key, versionId);
607	                byte[] result = s3SelectService.select(obj, new String(body, StandardCharsets.UTF_8));
608	                return Response.ok(result)
609	                        .type("application/octet-stream")
610	                        .build();
611	            }
612	
613	            if (uploadId != null) {
614	                List<Integer> partNumbers = parseCompleteMultipartBody(new String(body));
615	                S3Object obj = s3Service.completeMultipartUpload(bucket, key, uploadId, partNumbers);
616	                String baseUrl = uriInfo.getBaseUri().toString();
617	                if (baseUrl.endsWith("/")) {
618	                    baseUrl = baseUrl.substring(0, baseUrl.length() - 1);
619	                }
620	                XmlBuilder xmlBuilder = new XmlBuilder()
621	                        .raw("<?xml version=\"1.0\" encoding=\"UTF-8\"?>")
622	                        .start("CompleteMultipartUploadResult", AwsNamespaces.S3)
623	                        .elem("Location", baseUrl + "/" + bucket + "/" + key)
624	                        .elem("Bucket", bucket)
625	                        .elem("Key", key)
626	                        .elem("ETag", obj.getETag());
627	                if (obj.getVersionId() != null) {
628	                    xmlBuilder.elem("VersionId", obj.getVersionId());
629	                }
630	                String xml = xmlBuilder.end("CompleteMultipartUploadResult").build();
631	                var resp = Response.ok(xml);
632	                if (obj.getVersionId() != null) {
633	                    resp.header("x-amz-version-id", obj.getVersionId());
634	                }
635	                return resp.build();
636	            }
637	
638	            return xmlErrorResponse(new AwsException("InvalidArgument",
639	                    "POST requires either ?uploads, ?uploadId, ?restore or ?select parameter.", 400));
640	        } catch (AwsException e) {
641	            return xmlErrorResponse(e);
