1368	            // Look for content-length-range condition: ["content-length-range", min, max]
1369	            String lower = decoded.toLowerCase(Locale.ROOT);
1370	            int rangeIdx = lower.indexOf("content-length-range");
1371	            if (rangeIdx < 0) {
1372	                return;
1373	            }
1374	            // Find the enclosing array bracket
1375	            int bracketStart = decoded.lastIndexOf('[', rangeIdx);
1376	            int bracketEnd = decoded.indexOf(']', rangeIdx);
1377	            if (bracketStart < 0 || bracketEnd < 0) {
1378	                return;
1379	            }
1380	            String rangeArray = decoded.substring(bracketStart, bracketEnd + 1);
1381	            // Extract min and max values
1382	            String[] tokens = rangeArray.replaceAll("[\\[\\]\"]", "").split(",");
1383	            if (tokens.length >= 3) {
1384	                long min = Long.parseLong(tokens[1].trim());
1385	                long max = Long.parseLong(tokens[2].trim());
