1416	    private static List<byte[]> splitMultipartParts(byte[] body, byte[] boundary) {
1417	        java.util.ArrayList<byte[]> parts = new java.util.ArrayList<>();
1418	        int pos = indexOf(body, boundary, 0);
1419	        if (pos < 0) {
1420	            return parts;
1421	        }
1422	        // Skip past the first boundary line
1423	        pos += boundary.length;
1424	        // Skip the CRLF or -- after boundary
1425	        if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
1426	            return parts; // closing boundary immediately
1427	        }
1428	        if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
1429	            pos += 2;
1430	        }
1431	
1432	        while (pos < body.length) {
1433	            int nextBoundary = indexOf(body, boundary, pos);
1434	            if (nextBoundary < 0) {
1435	                break;
1436	            }
1437	            parts.add(Arrays.copyOfRange(body, pos, nextBoundary));
1438	            pos = nextBoundary + boundary.length;
1439	            // Check for closing boundary --
1440	            if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
1441	                break;
1442	            }
1443	            // Skip CRLF after boundary
1444	            if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
1445	                pos += 2;
1446	            }
1447	        }
1448	        return parts;
1449	    }
