1480	        int valueStart = idx + lowerName.length();
1481	        int lineEnd = headers.indexOf('\r', valueStart);
1482	        if (lineEnd < 0) {
1483	            lineEnd = headers.indexOf('\n', valueStart);
1484	        }
1485	        if (lineEnd < 0) {
